import * as React from 'react'
import { FormRelate as FormRelateComponent } from '@/registry/components/form-relate-component/form-relate-component'
import { RelateSelect } from '@/registry/components/form-relate-select/form-relate-select'
import { RelateMultiSelect } from '@/registry/components/form-relate-multi-select/form-relate-multi-select'
import { RelateModelSelect } from '@/registry/components/form-relate-model-select/form-relate-model-select'
import type { RelateFieldProps } from '@/registry/lib/form-relate-types'
import { useFormContext } from '@airiot/client'
import { Table2Context } from '@/registry/lib/table-context'
import { dealFilter } from '@/registry/lib/form-relate-utils'

/**
 * FormRelate - 关联字段容器组件
 * 根据 field.schema 配置自动分发到对应的子组件：
 * - FormRelateComponent: 内部表关联 (internalTable=true)
 * - RelateSelect: 外部工作表单选 (默认单选)
 * - RelateMultiSelect: 外部工作表多选 (selectType='multiple')
 * - RelateModelSelect: 弹窗表格选择 (有 relateShowFields)
 *
 * 对于内部表关联，此组件负责构建 filterObj 并传递给纯组件 FormRelateComponent
 */
const FormRelate: React.FC<RelateFieldProps> = (props) => {
  const { field = {}, relateSchema: schema = {}, value, onChange, meta, record, disabled, label } = props

  // 判断是否为内部表关联
  const isInternalTable = schema.internalTable !== false

  // 获取选择类型
  const selectType = schema.selectType || 'single'

  // 判断是否有多个展示字段（使用弹窗表格选择器）
  const hasMultiFields = schema.relateShowFields && schema.relateShowFields.length > 0

  // 判断是否为详情展示模式
  const isDetailShow = schema.recordSelectType === 'show'

  // 获取表单和表格上下文（用于构建 filterObj）
  const form = useFormContext()
  const outTable = React.useContext(Table2Context)

  const getFormState = () => {
    if (form) {
      return form.getValues()
    }
  }

  // 构建过滤器对象
  const filterObj = React.useMemo(() => {
    const result: Record<string, any> = {}
    dealFilter(result, field, getFormState, outTable)
    return result
  }, [field, form, outTable])

  // ==================== 分发逻辑 ====================

  // 1. 详情展示模式
  if (isDetailShow) {
    // TODO: 如果需要支持 DetailShow，可以在这里处理
    // 目前返回 null，由调用方处理
    return null
  }

  // 2. 内部表关联 - 使用 FormRelateComponent
  if (isInternalTable) {
    return (
      <FormRelateComponent
        value={value}
        onChange={onChange}
        field={field}
        schema={schema}
        meta={meta}
        record={record}
        disabled={disabled}
        filterObj={filterObj}
      />
    )
  }

  // 3. 外部表关联 - 根据是否有多字段和选择类型分发

  // 3.1 有多个展示字段 - 使用弹窗表格选择器
  if (hasMultiFields) {
    // 构建完整的 field 对象传给 RelateModelSelect
    const modelSelectField = {
      ...field,
      schema: {
        ...schema,
        name: schema.relate?.id ? `core/t/${schema.relate.id}/d` : undefined,
      },
      displayField: schema.relate?.fields?.[0]?.key || 'name',
    }

    return (
      <RelateModelSelect
        input={input}
        field={modelSelectField}
        meta={meta}
        record={record}
        disabled={disabled}
        label={label || schema.title}
        selectType={selectType}
        inputType={schema.inputType || 'select'}
        allFieldReturn={schema.allFieldReturn || false}
        insideFilter={schema.insideFilter}
      />
    )
  }

  // 3.2 多选模式 - 使用 RelateMultiSelect
  if (selectType === 'multiple') {
    const multiSelectField = {
      ...field,
      displayField: schema.relate?.fields?.[0]?.key || 'name',
      schema: {
        ...schema,
        name: schema.relate?.id ? `core/t/${schema.relate.id}/d` : undefined,
      },
    }

    return (
      <RelateMultiSelect
        input={input}
        field={multiSelectField}
        meta={meta}
        record={record}
        disabled={disabled}
        label={label || schema.title}
      />
    )
  }

  // 3.3 默认单选模式 - 使用 RelateSelect
  const selectField = {
    ...field,
    displayField: schema.relate?.fields?.[0]?.key || 'name',
    schema: {
      ...schema,
      name: schema.relate?.id ? `core/t/${schema.relate.id}/d` : undefined,
    },
  }

  return (
    <RelateSelect
      input={input}
      field={selectField}
      meta={meta}
      record={record}
      disabled={disabled}
      label={label || schema.title}
    />
  )
}

export { FormRelate }

/**
 * 关联字段相关的类型定义
 */

export interface RelateFieldOption {
  value: string
  label: string
  key?: string
  item?: any
}

export interface RelateFieldProps {
  value?: any
  onChange?: (value: any) => void
  field?: {
    schema?: Record<string, any>
    filter?: any
    meta?: any
    key?: string
    displayField?: string
    tableID?: string
    relateShowFields?: Array<{
      key: string
      title: string
      mapToCurrent?: boolean
      mapField?: string
      fieldSchema?: any
    }>
    option?: {
      form?: {
        change: (field: string, value: any) => void
      }
    }
  }
  schema?: Record<string, any>
  meta?: any
  record?: any
  antdForm?: any
  label?: string
  disabled?: boolean
}

export interface AsyncSelectProps extends RelateFieldProps {
  value?: {
    key: string
    label: string
    item?: any
  } | null
  mode?: 'multiple' | 'tags'
  isOptionSelected?: (option: RelateFieldOption) => boolean
  style?: React.CSSProperties
}

import React from "react";
import { createAPI } from '@airiot/client';

interface TableContextValue {
  list?: any[]
  tableInfo?: any
  editingSchema?: any
}

interface Table2ContextValue {
  editingSchema?: any
}

interface TCProviderProps {
  children: React.ReactNode
  id?: string
  editingSchema?: any
}

const TableContext = React.createContext<TableContextValue | undefined>(undefined)

const TCProvider: React.FC<TCProviderProps> = ({ children, id, editingSchema }) => {
  const [list, setList] = React.useState<any[]>()
  const [tableInfo, setTableInfo] = React.useState<any>()

  React.useEffect(() => {
    if (id) {
      const dataApi = createAPI({ resource: `core/t/${id}/d` })
      const schemaApi = createAPI({ resource: `core/t/schema/${id}` })

      dataApi.query({}).then(({ items }: any) => {
        setList(items)
      }).catch((err: Error) => {
        console.error(err)
      })

      schemaApi.fetch('').then((res: any) => {
        setTableInfo(res?.json)
      }).catch((err: Error) => {
        console.error(err)
      })
    }
  }, [id])

  return <TableContext.Provider value={{ list, tableInfo, editingSchema }}>
    {children}
  </TableContext.Provider>
}

// 表格控件，高级编辑中使用
const Table2Context = React.createContext<Table2ContextValue | undefined>(undefined)

const TC2Provider: React.FC<TCProviderProps> = ({ children, editingSchema }) => {
  return <Table2Context.Provider value={{ editingSchema }}>
    {children}
  </Table2Context.Provider>
}

export { TableContext, TCProvider, Table2Context, TC2Provider }

import isEmpty from 'lodash/isEmpty'
import isObject from 'lodash/isObject'
import isArray from 'lodash/isArray'
import { getQueryFilter } from './filter-utils'

/**
 * 在 tableSchema 中查找 value?.relate?.id 等于 tableID 的对应 key
 */
export const findRelateKeyInTableSchema = (tableSchema: any, tableID: string): string | null => {
  if (!tableSchema || !tableSchema.properties) {
    return null
  }

  for (const [key, property] of Object.entries(tableSchema.properties)) {
    if ((property as any)?.relate?.id === tableID) {
      return key
    }
  }

  return null
}

/**
 * 在树形数据中查找节点
 */
export const findTreeNode = (treeData: any[], value: any): any => {
  for (const node of treeData) {
    if (node.value === value) {
      return node
    }
    if (node.children && node.children.length > 0) {
      const found = findTreeNode(node.children, value)
      if (found) return found
    }
  }
  return null
}

/**
 * 替换字段占位符
 * 将 [field]:fieldName 或 [field][table]:fieldName 替换为实际值
 */
export const replaceFieldPlaceholders = (value: any, allValues: Record<string, any>): any => {
  if (typeof value === 'string') {
    // 处理 [field]:fieldName 占位符
    if (value.startsWith('[field]:')) {
      const key = value.substring(8)
      return allValues[key] !== undefined ? allValues[key] : value
    }
    // 处理 [field][table]:fieldName 占位符
    if (value.startsWith('[field][table]:')) {
      const key = value.substring(15)
      return allValues[key] !== undefined ? allValues[key] : value
    }
    return value
  }

  if (isArray(value)) {
    return value.map(item => replaceFieldPlaceholders(item, allValues))
  }

  if (isObject(value) && value !== null) {
    const result: Record<string, any> = {}
    for (const [key, val] of Object.entries(value)) {
      result[key] = replaceFieldPlaceholders(val, allValues)
    }
    return result
  }

  return value
}

/**
 * 处理过滤器
 * 将内置查询过滤器应用到 filterObj 中
 *
 * @param filterObj - 过滤器对象，会被修改
 * @param field - 字段配置
 * @param getFormState - 获取表单状态的函数
 * @param outTable - 外部表的 editingSchema（可选）
 */
export const dealFilter = (
  filterObj: Record<string, any>,
  field: any,
  getFormState?: () => any,
  outTable?: { editingSchema?: Record<string, any> }
) => {
  // 在过滤器中，如果没有设置 field.filter，则使用内置查询
  const ifFilter = field.filter

  // 设置了内置查询
  if (field.insideFilter && !ifFilter) {
    const inFilter = getQueryFilter(field.insideFilter, field.schema)
    const allValues = {
      ...(outTable?.editingSchema || {}),
      ...(getFormState?.()?.values || {})
    }

    // 确保 filterObj 有 search 属性
    if (!filterObj.search) {
      filterObj.search = {}
    }

    // 替换占位符并添加到搜索条件中
    for (const key in inFilter) {
      let insideVal = inFilter[key]
      const replacedVal = replaceFieldPlaceholders(insideVal, allValues)
      filterObj.search[key] = replacedVal
    }
  }
}

/**
 * 简单的 fieldRender 函数
 * 用于在列表中显示字段值
 */
export const fieldRender = (value: any, _schema?: any): React.ReactNode => {
  // 字符串、数字、布尔值直接显示
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    return value
  }

  // 对象显示 .name
  if (isObject(value) && !isArray(value)) {
    return (value as any).name ?? (value as any).id ?? JSON.stringify(value)
  }

  // 数组显示 .name join(',')
  if (isArray(value)) {
    return value
      .map(item => {
        if (typeof item === 'string' || typeof item === 'number') {
          return item
        }
        if (isObject(item)) {
          return (item as any).name ?? (item as any).id
        }
        return JSON.stringify(item)
      })
      .filter(Boolean)
      .join(',')
  }

  // 空值处理
  if (isEmpty(value)) {
    return null
  }

  return JSON.stringify(value)
}

/**
 * 获取表单状态 - 用于获取其他字段的值
 * 类似于 use('form') 的功能
 */
export const getFormState = (formState: any, currentFieldKey?: string) => {
  // TODO: 实现表单状态获取逻辑
  // 这个函数应该从 form state 中获取其他字段的值
  // 用于字段联动和脚本计算
  if (!formState) {
    return {}
  }

  const values: Record<string, any> = {}
  for (const key in formState.values) {
    // 跳过当前字段，避免循环依赖
    if (key !== currentFieldKey) {
      values[key] = formState.values[key]
    }
  }

  return { values }
}

/**
 * 获取表单所有值 - 用于字段脚本
 */
export const getFormValues = (schema: any, formState?: any) => {
  if (!formState) {
    return null
  }

  const values: Record<string, any> = {}
  for (const key in formState.values) {
    if (key !== schema.key) {
      values[key] = formState.values[key]
    }
  }

  return values
}
